// n8n Code node (JavaScript)
// Siempre crea FechaInicio/FechaFin desde FechaActual (14:00 / 10:00, -03:00)
// Mantiene FechaNuevaInicio/Final si ya vienen.
// Genera FechaNuevaRango humano.

const FIXED_OFFSET = "-03:00";

const monthMap = {
  'enero':1,'febrero':2,'marzo':3,'abril':4,'mayo':5,'junio':6,
  'julio':7,'agosto':8,'septiembre':9,'setiembre':9,'octubre':10,
  'noviembre':11,'diciembre':12,
  'ene':1,'feb':2,'mar':3,'abr':4,'may':5,'jun':6,
  'jul':7,'ago':8,'sep':9,'oct':10,'nov':11,'dic':12,
};
const MONTHS_ES = ['', 'enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];

const norm = (s='') => s.toString().trim().toLowerCase().normalize('NFD').replace(/\p{Diacritic}/gu,'');
const pad2 = n => String(n).padStart(2,'0');
const toISOFixed = (y,m,d,hh,mm,ss,offset) => `${y}-${pad2(m)}-${pad2(d)}T${pad2(hh)}:${pad2(mm)}:${pad2(ss)}${offset}`;

function parseRangoDesdeTexto(textoRaw) {
  const t = norm(textoRaw ?? '');
  const now = new Date();
  const yM = t.match(/(20\d{2}|19\d{2})/);
  const year = yM ? parseInt(yM[1],10) : now.getFullYear();
  const mKey = Object.keys(monthMap).find(k => t.includes(k));
  const month = mKey ? monthMap[mKey] : null;
  let r = t.match(/(?:\bdel?\s*)?(\d{1,2})\s*(?:al|-|a)\s*(\d{1,2})\b/);
  let s = null;
  if (!r) s = t.match(/\b(\d{1,2})\b/);
  if (!month || (!r && !s)) return null;
  let d1, d2;
  if (r) { d1 = parseInt(r[1],10); d2 = parseInt(r[2],10); }
  else   { d1 = parseInt(s[1],10);  d2 = d1; }
  if (d2 < d1) [d1,d2] = [d2,d1];
  return { year, month, d1, d2 };
}

function parseISODateOnly(iso) {
  if (!iso) return null;
  const m = String(iso).match(/^(\d{4})-(\d{2})-(\d{2})/);
  if (!m) return null;
  return { y:+m[1], m:+m[2], d:+m[3] };
}

function formatRangeEs(a, b) {
  if (!a || !b) return null;
  const sameDay = a.y===b.y && a.m===b.m && a.d===b.d;
  const sameMonth = a.y===b.y && a.m===b.m;
  const mesA = MONTHS_ES[a.m], mesB = MONTHS_ES[b.m];
  if (sameDay) return `el ${a.d} de ${mesA}`;
  if (sameMonth) return `del ${a.d} al ${b.d} de ${mesA}`;
  if (a.y === b.y) return `del ${a.d} de ${mesA} al ${b.d} de ${mesB}`;
  return `del ${a.d} de ${mesA} de ${a.y} al ${b.d} de ${mesB} de ${b.y}`;
}

for (const item of $input.all()) {
  // 1) Siempre parsea FechaActual -> FechaInicio/FechaFin
  const textoActual = item.json.FechaActual ?? item.json.FechaReserva ?? item.json.FechaNueva ?? '';
  const r = parseRangoDesdeTexto(textoActual);
  if (r) {
    item.json.FechaInicio = toISOFixed(r.year, r.month, r.d1, 14, 0, 0, FIXED_OFFSET);
    item.json.FechaFin    = toISOFixed(r.year, r.month, r.d2, 10, 0, 0, FIXED_OFFSET);
  } else {
    // no se pudo parsear -> deja nulos si no estaban
    if (item.json.FechaInicio === undefined) item.json.FechaInicio = null;
    if (item.json.FechaFin === undefined)    item.json.FechaFin    = null;
  }

  // 2) Texto humano: prioriza las nuevas; si no hay, usa las actuales
  const startRaw = (item.json.FechaNuevaInicio ?? item.json.FechaInicio) || null;
  const endRaw   = (item.json.FechaNuevaFinal  ?? item.json.FechaFin)   || null;
  const a = parseISODateOnly(startRaw);
  const b = parseISODateOnly(endRaw);
  const rangoHumano = formatRangeEs(a, b);

  item.json.FechaNuevaRango       = rangoHumano;
  item.json.FechaNuevaInicioHuman = rangoHumano;
  item.json.FechaNuevaFinalHuman  = rangoHumano;
}

return $input.all();
